const mapping = {
  'मेष': 'aries',
  'वृषभ': 'taurus',
  'मिथुन': 'gemini',
  'कर्क': 'cancer',
  'सिंह': 'leo',
  'कन्या': 'virgo',
  'तुला': 'libra',
  'वृश्चिक': 'scorpio',
  'धनु': 'sagittarius',
  'मकर': 'capricorn',
  'कुंभ': 'aquarius',
  'मीन': 'pisces'
};
const hindiSign = $node["Split Signs"].json["signs"];
return [{
  json: {
    sign: hindiSign,
    english_sign: mapping[hindiSign] || hindiSign.toLowerCase(),
    content: $json.choices[0].message.content.trim()
  }
}];

const fs = require('fs');
const englishSign = $node["Extract Content"].json.english_sign || 'unknown';
const filePath = `/root/.n8n-files/${englishSign}.mp4`;

// Ensure directory exists
if (!fs.existsSync('/root/.n8n-files/')){
    fs.mkdirSync('/root/.n8n-files/', { recursive: true });
}

fs.copyFileSync('/data/n8n-work/dummy.mp4', filePath);

return [{
  json: {
    ...$json,
    saved_file: filePath,
    dummy_mode: true
  }
}];

try {
    const https = require('https');
    const fs = require('fs');
    const uploadUrl = $input.first().json.upload_url;

    // Secure Access Token via Memory
    const accessToken = $env.FACEBOOK_PAGE_ACCESS_TOKEN.trim();

    // Identify the dynamic video file name
    const englishSign = $('Extract Content').first().json.english_sign;
    const filePath = "/root/.n8n-files/" + englishSign + ".mp4";

    if (!fs.existsSync(filePath)) {
        throw new Error("Could not find video at: " + filePath);
    }

    // Natively read the binary bytes from disk
    const binaryBuffer = fs.readFileSync(filePath);

    // Manually split the URL into Hostname and Path to bypass the missing URL class
    const urlWithoutProtocol = uploadUrl.substring(8);
    const firstSlashIndex = urlWithoutProtocol.indexOf('/');
    const hostname = urlWithoutProtocol.substring(0, firstSlashIndex);
    const path = urlWithoutProtocol.substring(firstSlashIndex);

    const options = {
        hostname: hostname,
        path: path,
        method: 'POST',
        headers: {
            'Authorization': `OAuth ${accessToken}`,
            'offset': '0',
            'file_size': binaryBuffer.length.toString(),
            'Content-Length': binaryBuffer.length.toString(),
            // THIS is the secret header that Facebook's server requires to parse the payload properly!
            'Content-Type': 'application/x-www-form-urlencoded',
            'Connection': 'keep-alive',
            'Accept': '*/* '
        }
    };

    return await new Promise((resolve, reject) => {
        const req = https.request(options, (res) => {
            let responseData = '';
            res.on('data', (chunk) => responseData += chunk);
            res.on('end', () => resolve([{ json: { body: responseData, status: res.statusCode } }]));
        });

        req.on('error', (e) => resolve([{ json: { execute_error: e.message } }]));
        req.write(binaryBuffer);
        req.end();
    });

} catch (masterError) {
    return [{ json: { CRASH: masterError.message, stack: masterError.stack } }];
}

if ($json.error) {
  throw new Error(`FACEBOOK API ERROR: ${$json.error.message} (Type: ${$json.error.type})`);
}
if (!$json.success) {
  throw new Error(`FACEBOOK PUBLISH FAILED: Success flag not received. Response: ${JSON.stringify($json)}`);
}
return [{
  json: {
    facebook_success: true,
    video_id: $node["Initialize Reel"].json.video_id,
    raw_response: $json
  }
}];

const https = require('https');

const videoId = $node["Initialize Reel"].json.video_id;
const description = $node["Extract Content"].json.content;
const pageId = $env.FACEBOOK_PAGE_ID;

// Securely access Token globally via Docker Env Mapping
const accessToken = $env.FACEBOOK_PAGE_ACCESS_TOKEN.trim();

console.log("Access Token:", accessToken)
const payload = JSON.stringify({
    upload_phase: 'finish',
    video_id: videoId,
    video_state: 'PUBLISHED',
    description: description,
    access_token: accessToken    // THIS WAS THE MISSING KEY CAUSING THE NULL CRASH!
});

const options = {
    hostname: 'graph.facebook.com',
    path: `/v18.0/${pageId}/video_reels`, // Clean URL, no query string
    method: 'POST',
    headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(payload)
    }
};

return await new Promise((resolve, reject) => {
    const req = https.request(options, (res) => {
        let responseData = '';
        res.on('data', chunk => responseData += chunk);
        res.on('end', () => resolve([{ json: { body: JSON.parse(responseData || '{}'), status: res.statusCode } }]));
    });
    req.on('error', e => resolve([{ json: { execute_error: e.message } }]));
    req.write(payload);
    req.end();
});
